import { Plus, Upload, Users } from "lucide-react";
import { AppShell } from "@/components/layout/app-shell";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";

export const metadata = { title: "Vendor Order Portal", description: "Secure lender and vendor order intake with document uploads and restricted visibility." };
const uploads = ['Purchase contract','Engagement letter','MLS sheets','Borrower contact sheet','Builder plans/specs','Additional lender instructions'];
export default function VendorsPage() { return <AppShell title="Vendor Portal"><div className="grid gap-6 xl:grid-cols-[1.1fr_.9fr]"><Card><CardContent className="p-6"><div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between"><div><h3 className="text-lg font-semibold">Vendor order portal</h3><p className="text-sm text-slate-500">Lenders, AMCs, and vendor clients can securely place orders and upload required documents without seeing internal operations.</p></div><Button><Plus size={16} className="mr-2"/>Place Order</Button></div><div className="mt-6 grid gap-4 md:grid-cols-2 xl:grid-cols-3">{uploads.map(title => <div key={title} className="rounded-2xl border border-slate-200 p-4"><Upload size={18}/><p className="mt-3 font-medium">{title}</p><p className="mt-2 text-sm text-slate-500">Upload and attach directly to the appraisal order.</p></div>)}</div><div className="mt-6 rounded-2xl border border-slate-200 bg-slate-50 p-5"><div className="flex items-start gap-3"><Users className="mt-1" size={20}/><div><p className="font-medium">Vendor-restricted visibility</p><p className="mt-1 text-sm leading-6 text-slate-500">Vendor users only see orders tied to their own company. They cannot access internal review findings, accounting, or unrelated appraiser data.</p></div></div></div></CardContent></Card><Card><CardContent><h3 className="font-semibold">Vendor workflow</h3><div className="mt-4 space-y-3">{[['Create order','Upload order packet + borrower docs'],['Track progress','Inspection, review, and delivery status'],['Secure messaging','Communicate with operations team'],['Final delivery','Download completed report and XML package']].map(([a,b]) => <div key={a} className="rounded-2xl border border-slate-200 p-4"><p className="font-medium">{a}</p><p className="mt-1 text-sm text-slate-500">{b}</p></div>)}</div></CardContent></Card></div></AppShell>; }
